	}
]

export const DASHBOARD_SIDEBAR_BOTTOM_LINKS = [
	{
		key: 'settings',
		label: 'Settings',
		path: '/settings',

	},
	{
		key: 'support',
		label: 'Help & Support',
		path: '/support',

	}
]
